I have designed the new "Shadcn Assistant" UI mode. Since my file modification tools are currently unavailable in this environment, you can apply these changes by creating and updating the following files:

### 1. Create `apps/web/src/ui-modes/shadcn/index.tsx`
Create a new directory `apps/web/src/ui-modes/shadcn` and add the following `index.tsx` file to define the Shadcn-style components:

```tsx
import React from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { Plus, Settings as SettingsIcon, Trash2, Check, Copy, X, File as FileIcon, RotateCcw, Folder, MessageSquare, Send } from 'lucide-react';
import Mermaid from '../../components/Mermaid';
import CollapsibleCode from '../../components/CollapsibleCode';
import DiffViewer from '../../components/DiffViewer';
import { ChatLayoutProps, MessageBubbleProps, ChatInputProps, UIModeComponents } from '../types';

export const ShadcnSidebar = ({ 
  projects, selectedProject, setSelectedProject, setIsAddingProject,
  chats, selectedChat, setSelectedChat, handleCreateChat, handleDeleteChat, setShowSettings 
}: any) => (
  <div className="flex flex-col h-full bg-slate-50 text-slate-900 p-3 gap-4 border-r border-slate-200 w-[260px]">
    <button 
      onClick={handleCreateChat}
      className="w-full flex items-center justify-center gap-2 rounded-xl border border-slate-200 px-4 py-2 hover:bg-slate-100 transition-colors bg-white shadow-sm font-medium"
    >
      <Plus className="w-4 h-4" /> New Thread
    </button>

    <div className="flex-1 overflow-y-auto space-y-6">
      <div>
        <div className="text-xs font-semibold text-slate-500 mb-2 px-2 uppercase tracking-wider">Projects</div>
        <div className="space-y-1">
          {projects.map((p: string) => (
            <button 
              key={p}
              onClick={() => { setSelectedProject(p); setSelectedChat(null); }}
              className={`w-full text-left flex items-center gap-2 px-3 py-2 rounded-lg text-sm ${selectedProject === p ? 'bg-slate-200 font-medium text-slate-900' : 'text-slate-600 hover:bg-slate-100'}`}
            >
              <Folder className="w-4 h-4" /> {p}
            </button>
          ))}
        </div>
      </div>

      {selectedProject && chats.length > 0 && (
        <div>
          <div className="text-xs font-semibold text-slate-500 mb-2 px-2 uppercase tracking-wider">Threads</div>
          <div className="space-y-1">
            {chats.map((c: any) => (
              <div key={c.id} className="group relative">
                <button 
                  onClick={() => setSelectedChat(c)}
                  className={`w-full text-left flex items-center gap-2 px-3 py-2 rounded-lg text-sm truncate pr-8 ${selectedChat?.id === c.id ? 'bg-slate-200 font-medium text-slate-900' : 'text-slate-600 hover:bg-slate-100'}`}
                >
                  <MessageSquare className="w-4 h-4 shrink-0" />
                  <span className="truncate">{c.title}</span>
                </button>
                <button
                  onClick={(e) => handleDeleteChat(e, c.id)}
                  className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 text-slate-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                  title="Delete thread"
                >
                  <Trash2 className="w-3.5 h-3.5" />
                </button>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>

    <div className="mt-auto pt-2 border-t border-slate-200">
      <button onClick={() => setShowSettings(true)} className="flex items-center gap-2 text-sm text-slate-600 hover:text-slate-900 p-2 rounded-lg hover:bg-slate-100 w-full transition-colors">
        <SettingsIcon className="w-4 h-4" /> Settings
      </button>
    </div>
  </div>
);

export const ShadcnHeader = ({ model, setModel, fallbackStatus }: any) => (
  <header className="h-14 flex items-center justify-center border-b border-slate-200 bg-white px-4">
    {fallbackStatus && (
      <span className="text-amber-500 animate-pulse font-medium mr-4 flex items-center gap-1 text-sm">
        <span className="w-2 h-2 bg-amber-500 rounded-full"></span>
        {fallbackStatus}
      </span>
    )}
    <div className="flex items-center gap-2 rounded-full border border-slate-200 px-4 py-1.5 text-sm hover:bg-slate-50 cursor-pointer text-slate-700 shadow-sm">
      <select value={model} onChange={e => setModel(e.target.value)} className="bg-transparent border-none outline-none appearance-none cursor-pointer pr-4 font-medium">
        <option value="gemini-3.1-pro-preview">Gemini 3.1 Pro Preview</option>
        <option value="gemini-3-pro-preview">Gemini 3 Pro Preview</option>
        <option value="gemini-3-flash-preview">Gemini 3 Flash Preview</option>
        <option value="gemini-2.5-pro">Gemini 2.5 Pro</option>
        <option value="gemini-2.5-flash">Gemini 2.5 Flash</option>
        <option value="gemini-2.5-flash-lite">Gemini 2.5 Flash Lite</option>
      </select>
    </div>
  </header>
);

export const ShadcnSuggestions = ({ onSelect }: any) => {
  const suggestions = [
    { title: "Review my code", description: "Analyze the current file for bugs and improvements." },
    { title: "Explain architecture", description: "Give me an overview of the project structure." }
  ];
  return (
    <div className="flex flex-col items-center justify-center mt-20 mb-8 w-full max-w-2xl mx-auto px-4">
      <h2 className="text-2xl font-semibold mb-2 text-slate-800">How can I help you today?</h2>
      <p className="text-slate-500 mb-8">Select a prompt or type your own to get started.</p>
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 w-full">
        {suggestions.map((s, i) => (
          <button 
            key={i} 
            onClick={() => onSelect(s.title + " - " + s.description)}
            className="text-left rounded-xl border border-slate-200 p-4 hover:bg-slate-50 cursor-pointer transition-colors shadow-sm"
          >
            <div className="font-medium text-slate-800 mb-1">{s.title}</div>
            <div className="text-sm text-slate-500">{s.description}</div>
          </button>
        ))}
      </div>
    </div>
  );
};

export const ShadcnLayout: React.FC<ChatLayoutProps> = ({ sidebar, header, messages, input, children }) => (
  <div className="flex h-screen font-sans bg-white text-slate-900">
    {sidebar}
    <div className="flex-1 flex flex-col min-w-0 bg-white">
      {header}
      <div className="flex-1 overflow-hidden relative flex flex-col items-center">
        <div className="w-full max-w-[800px] flex-1 flex flex-col overflow-hidden">
          {messages}
        </div>
        <div className="w-full max-w-[800px] pb-6 px-4">
          {input}
        </div>
      </div>
    </div>
    {children}
  </div>
);

export const ShadcnMessage: React.FC<MessageBubbleProps> = ({ message, index, isStreaming, renderMermaid, onRetry }) => {
  const isUser = message.role === 'user';
  const [copied, setCopied] = React.useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(message.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className={`flex gap-4 w-full ${isUser ? 'flex-row-reverse' : ''} mb-8`}>
      <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 text-white shadow-sm ${isUser ? 'bg-slate-800' : 'bg-blue-600'}`}>
        {isUser ? 'U' : 'AI'}
      </div>
      <div className={`flex-1 overflow-hidden ${isUser ? 'flex flex-row-reverse items-end gap-2' : 'space-y-2'}`}>
        <div className={`inline-block text-left max-w-full overflow-x-auto ${isUser ? 'bg-slate-100 rounded-2xl px-5 py-3 text-slate-900' : 'text-slate-800'}`}>
          <div className={`prose max-w-none prose-p:leading-relaxed text-base ${isUser ? 'prose-p:my-0' : ''}`}>
            <ReactMarkdown
              remarkPlugins={[remarkGfm]}
              components={{
                code({ node, inline, className, children, ...props }: any) {
                  const match = /language-(\w+)/.exec(className || '');
                  const language = match ? match[1] : '';
                  const codeString = String(children).replace(/\n$/, '');

                  if (!inline && language === 'mermaid' && renderMermaid) {
                    return <Mermaid chart={codeString} />;
                  }
                  if (!inline && language === 'diff') {
                    return <DiffViewer diffText={codeString} showActions={false} />;
                  }

                  return !inline && match ? (
                    <CollapsibleCode language={language} value={codeString} />
                  ) : (
                    <code {...props} className="bg-slate-100 px-1.5 py-0.5 rounded-md text-sm font-mono border border-slate-200">
                      {children}
                    </code>
                  )
                }
              }}
            >
              {message.content + (isStreaming ? '...' : '')}
            </ReactMarkdown>
          </div>
        </div>

        {isUser ? (
          <div className="flex flex-col gap-1 mb-1 shrink-0">
            {onRetry && !isStreaming && (
              <button onClick={() => onRetry(index)} className="text-slate-400 hover:text-slate-600 transition-colors" title="Retry">
                <RotateCcw className="w-3.5 h-3.5" />
              </button>
            )}
          </div>
        ) : (
          !isStreaming && (
            <div className="flex items-center gap-2 mt-2">
              <button onClick={handleCopy} className="text-xs text-slate-500 hover:text-slate-700 flex items-center gap-1.5 transition-colors bg-slate-100 px-2 py-1 rounded-md border border-slate-200">
                {copied ? <Check className="w-3 h-3 text-green-500" /> : <Copy className="w-3 h-3" />}
                {copied ? 'Copied' : 'Copy'}
              </button>
            </div>
          )
        )}
      </div>
    </div>
  );
};

export const ShadcnInput: React.FC<ChatInputProps> = ({
  input, setInput, onSend, isGenerating, selectedChat, attachments, toggleAttachment,
  projectFiles, showFilePicker, setShowFilePicker, mentionState, filteredFiles,
  selectMention, handleInputChange, handleKeyDown
}) => (
  <div className="w-full bg-white">
    <div className="max-w-[800px] mx-auto flex flex-col gap-2 relative">
      {attachments.length > 0 && (
        <div className="flex flex-wrap gap-2 mb-2 absolute bottom-full left-0 pb-2">
          {attachments.map(att => (
            <div key={att} className="flex items-center gap-1 bg-slate-100 px-3 py-1.5 rounded-lg text-sm border border-slate-200 shadow-sm">
              <FileIcon className="w-3.5 h-3.5 text-slate-500" />
              <span className="truncate max-w-[200px] text-slate-700">{att.split('/').pop() || att}</span>
              <button onClick={() => toggleAttachment(att)} className="text-slate-400 hover:text-slate-600 ml-1"><X className="w-3.5 h-3.5" /></button>
            </div>
          ))}
        </div>
      )}

      <div className="relative flex items-end gap-2 p-3 rounded-2xl border border-slate-200 bg-slate-50 focus-within:border-slate-400 transition-colors shadow-sm">
        <div className="relative shrink-0">
          <button 
            onClick={() => setShowFilePicker(!showFilePicker)}
            className="p-2 text-slate-400 hover:text-slate-600 bg-white hover:bg-slate-100 rounded-full border border-slate-200 transition-colors flex items-center justify-center w-9 h-9"
          >
            <Plus className="w-4 h-4" />
          </button>
          {showFilePicker && (
            <div className="absolute bottom-full left-0 mb-3 w-64 max-h-64 overflow-y-auto bg-white border border-slate-200 rounded-xl shadow-xl p-2 z-10">
              <div className="text-xs font-semibold text-slate-500 mb-2 px-2">Attach Files</div>
              {projectFiles.length === 0 ? (
                <div className="text-xs text-slate-400 px-2">No files found</div>
              ) : (
                projectFiles.map(f => (
                  <button 
                    key={f} 
                    onClick={() => { toggleAttachment(f); setShowFilePicker(false); }}
                    className="w-full text-left px-2 py-1.5 text-sm text-slate-700 hover:bg-slate-100 rounded-lg truncate flex items-center justify-between transition-colors"
                  >
                    <span className="truncate">{f}</span>
                    {attachments.includes(f) && <Check className="w-4 h-4 text-slate-900" />}
                  </button>
                ))
              )}
            </div>
          )}
        </div>

        <textarea
          value={input}
          onChange={handleInputChange}
          onKeyDown={handleKeyDown}
          placeholder={selectedChat ? "Message Assistant..." : "Select or create a chat to begin..."}
          disabled={!selectedChat || isGenerating}
          className="flex-1 max-h-[200px] min-h-[24px] bg-transparent border-none focus:outline-none resize-none py-1.5 text-base placeholder-slate-400 text-slate-900"
          rows={Math.min(8, Math.max(1, input.split('\n').length))}
        />

        {mentionState.active && (
          <div className="absolute bottom-full mb-3 left-12 w-80 bg-white border border-slate-200 rounded-xl shadow-xl overflow-hidden z-50">
            <div className="p-2 border-b border-slate-100 text-xs font-semibold text-slate-500 bg-slate-50">
              Mention File
            </div>
            <ul className="max-h-60 overflow-y-auto p-1">
              {filteredFiles.length > 0 ? (
                filteredFiles.map((f, i) => (
                  <li key={f}>
                    <button
                      onClick={() => selectMention(f)}
                      className={`w-full text-left px-3 py-2 text-sm rounded-lg flex items-center gap-2 truncate transition-colors ${
                        i === mentionState.index ? 'bg-slate-100 text-slate-900 font-medium' : 'text-slate-600 hover:bg-slate-50'
                      }`}
                    >
                      <FileIcon className="w-4 h-4 shrink-0 opacity-70" />
                      <span className="truncate">{f}</span>
                    </button>
                  </li>
                ))
              ) : (
                <li className="px-3 py-4 text-center text-sm text-slate-400">No matching files found</li>
              )}
            </ul>
          </div>
        )}

        <button 
          onClick={() => onSend()}
          disabled={!input.trim() || !selectedChat || isGenerating}
          className={`shrink-0 w-9 h-9 rounded-full flex items-center justify-center transition-all ${
            input.trim() && selectedChat && !isGenerating 
              ? 'bg-slate-900 text-white hover:opacity-90 shadow-md' 
              : 'bg-slate-200 text-slate-400 cursor-not-allowed'
          }`}
        >
          <Send className="w-4 h-4 ml-0.5" />
        </button>
      </div>
      <div className="text-center text-xs text-slate-400 mt-2">
        Assistant can make mistakes. Consider verifying important information.
      </div>
    </div>
  </div>
);

export const ShadcnMode: UIModeComponents = {
  ChatLayout: ShadcnLayout,
  MessageBubble: ShadcnMessage,
  ChatInput: ShadcnInput
};
