export const ShadcnMessage: React.FC<MessageBubbleProps> = ({ message, index, isStreaming, renderMermaid, onRetry }) => {
  const isUser = message.role === 'user';
  const [copied, setCopied] = React.useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(message.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className={`flex gap-4 w-full ${isUser ? 'flex-row-reverse' : ''} mb-8`}>
      <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 text-white shadow-sm ${isUser ? 'bg-slate-800' : 'bg-blue-600'}`}>
        {isUser ? 'U' : 'AI'}
      </div>
      <div className={`flex-1 overflow-hidden ${isUser ? 'flex flex-row-reverse items-end gap-2' : 'space-y-2'}`}>
        <div className={`inline-block text-left max-w-full overflow-x-auto ${isUser ? 'bg-slate-100 rounded-2xl px-5 py-3 text-slate-900' : 'text-slate-800'}`}>
          <div className={`prose max-w-none prose-p:leading-relaxed text-base ${isUser ? 'prose-p:my-0' : ''}`}>
            <ReactMarkdown
              remarkPlugins={[remarkGfm]}
              components={{
                code({ node, inline, className, children, ...props }: any) {
                  const match = /language-(\w+)/.exec(className || '');
                  const language = match ? match[1] : '';
                  const codeString = String(children).replace(/\n$/, '');

                  if (!inline && language === 'mermaid' && renderMermaid) {
                    return <Mermaid chart={codeString} />;
                  }
                  if (!inline && language === 'diff') {
                    return <DiffViewer diffText={codeString} showActions={false} />;
                  }

                  return !inline && match ? (
                    <CollapsibleCode language={language} value={codeString} />
                  ) : (
                    <code {...props} className="bg-slate-100 px-1.5 py-0.5 rounded-md text-sm font-mono border border-slate-200">
                      {children}
                    </code>
                  )
                }
              }}
            >
              {message.content + (isStreaming ? '...' : '')}
            </ReactMarkdown>
          </div>
        </div>

        {isUser ? (
          <div className="flex flex-col gap-1 mb-1 shrink-0">
            {onRetry && !isStreaming && (
              <button onClick={() => onRetry(index)} className="text-slate-400 hover:text-slate-600 transition-colors" title="Retry">
                <RotateCcw className="w-3.5 h-3.5" />
              </button>
            )}
          </div>
        ) : (
          !isStreaming && (
            <div className="flex items-center gap-2 mt-2">
              <button onClick={handleCopy} className="text-xs text-slate-500 hover:text-slate-700 flex items-center gap-1.5 transition-colors bg-slate-100 px-2 py-1 rounded-md border border-slate-200">
                {copied ? <Check className="w-3 h-3 text-green-500" /> : <Copy className="w-3 h-3" />}
                {copied ? 'Copied' : 'Copy'}
              </button>
            </div>
          )
        )}
      </div>
    </div>
  );
};

